-- Migración 022: Tabla plana para la página Immigration Evaluations (pageId=immigration-evaluations).
-- 2 filas: locale 'en' y 'es'. Contenido extraído de src/pages/services/immigration-evaluations.astro (no existía en page_content).
--
-- ========== QUÉ HACER ==========
-- 1. Ejecutar este script en la misma BD que usa public/api/content.php.
-- 2. Después: en content.php añadir GET/PUT para pageId=immigration-evaluations; en contentDbService.server.ts
--    implementar getImmigrationEvaluationsContentFromDb() y rama en getPageContentFromDb(); opcionalmente
--    refactorizar immigration-evaluations.astro para consumir contenido desde la API.
--
-- ========== ESTRUCTURA ==========
-- Hero (title, description), intro_text, specializations_json (array de { id, title, description }),
-- faq_json (array de { question, answer?, paragraphs?, isSource? }), cta (title, subtitle, buttonText).
-- meta.lastUpdated en ISO 8601 para evitar ZodError.
-- Ejecutar en la misma BD que public/api/content.php (phpMyAdmin o CLI).

CREATE TABLE IF NOT EXISTS page_immigration_evaluations (
  id INT AUTO_INCREMENT PRIMARY KEY,
  locale VARCHAR(5) NOT NULL UNIQUE COMMENT 'en or es',
  meta_last_updated VARCHAR(32),
  meta_version INT DEFAULT 1,
  seo_title VARCHAR(255) DEFAULT '',
  seo_description TEXT,
  hero_title VARCHAR(255) NOT NULL DEFAULT 'Immigration Evaluations',
  hero_description TEXT COMMENT 'Subtitle/description under hero title',
  intro_text LONGTEXT COMMENT 'First paragraph below hero',
  specializations_json LONGTEXT NOT NULL COMMENT 'JSON array: [{ id, title, description }] for this locale',
  faq_json LONGTEXT NOT NULL COMMENT 'JSON array: [{ question, answer?, paragraphs?, isSource? }] for this locale',
  cta_title VARCHAR(255) DEFAULT '',
  cta_subtitle TEXT,
  cta_button_text VARCHAR(128) DEFAULT '',
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- INSERT con datos extraídos de immigration-evaluations.astro (en/es).
INSERT INTO page_immigration_evaluations (locale, meta_last_updated, meta_version, seo_title, seo_description, hero_title, hero_description, intro_text, specializations_json, faq_json, cta_title, cta_subtitle, cta_button_text) VALUES
('en', '2024-01-15T10:00:00Z', 1, 'Immigration Evaluations - Whole Self Counseling', '', 'Immigration Evaluations', 'Thorough psychological assessments utilized in immigration cases to aid courts in determining eligibility for individuals to legally remain in the United States.', 'Our immigration evaluations provide crucial evidence of trauma impact in asylum cases, U- or T-visas, and outline the hardships associated with family member deportation.', '[{"id":"political-asylum","title":"Political Asylum","description":"For individuals seeking asylum based on mistreatment or abuse related to political beliefs, religious affiliation, ethnic identity, or gender in their country of origin."},{"id":"vawa","title":"Violence against Women Act (VAWA)","description":"For individuals without documentation who have experienced abuse by their U.S. Citizen spouse."},{"id":"u-visa","title":"U-Visa","description":"For victims of violent crimes in the U.S. who have suffered mental or physical harm and are assisting law enforcement."},{"id":"t-visa","title":"T-Visa","description":"For victims of human trafficking (and their immediate family) willing to assist law enforcement."},{"id":"hardship-waivers","title":"Hardship Waivers","description":"For U.S. citizens or residents applying for a waiver due to the extreme hardship caused by the deportation of a family member."}]', '[{"question":"Process of Evaluation","paragraphs":["The immigration evaluation involves in-depth interviews over two to three sessions (depending on the needs of the person), covering personal, marital, family, work, medical, and psychiatric history.","Objective assessments may include PTSD surveys, personality inventories, mental status measures, self-report measures for various conditions, health inventories, partner violence surveys, measures of violent behavior, and achievement assessments. The final output is a 6–10-page comprehensive psychological evaluation."]},{"question":"Evaluator Information","answer":"Our practice is proud to have a team of BIPOC (Black, Indigenous, and People of Color) therapists who bring extensive experience in working with immigrant communities. Our diverse group of therapists understands the unique challenges faced by individuals from various cultural backgrounds and is committed to providing culturally sensitive and inclusive mental health support. We believe in creating a welcoming and affirming space where clients can feel understood, respected, and supported on their journey toward mental well-being."},{"question":"Interpreter Services","answer":"Clients are welcome to bring interpreters, and if need of one, Whole Self might be able to assist in identifying for the clients for an additional fee for the service."},{"question":"Cost and Duration","answer":"Unless under special circumstances, immigration evaluations are priced at $500. Most evaluations are completed within two weeks after the final interview."},{"question":"Insurance","answer":"At Whole Self, we understand the importance of accessibility to mental health services. Depending on the circumstances, we may be able to bill insurance companies for the services provided. It''s important to note that clients will be responsible for covering any remaining balance not paid by the insurance companies. We are committed to working with clients to explore available insurance options and ensure that mental health support is as financially accessible as possible. Feel free to reach out to our team for further details and assistance in navigating insurance coverage for the services you receive."},{"question":"Importance of Evaluation","paragraphs":["Psychological evaluations significantly enhance the chances of remaining in the United States. Recent studies indicate a 75.4% positive outcome for applicants with evaluations compared to the national asylum grant rate of 42.4%.","Source: Holly G. Atkinson, Katarzyna Wyka, Kathryn Hampton, Christian L. Seno, Elizabeth T. Yim, Deborah Ottenheimer, Nermeen S. Arastu, Impact of forensic medical evaluations on immigration relief grant rates and correlates of outcomes in the United States, Journal of Forensic and Legal Medicine, Volume 84, 2021, 102272, ISSN 1752-928X, https://doi.org/10.1016/j.jflm.2021.102272."],"isSource":true},{"question":"Working with Law Firms","answer":"We collaborate with both individual clients and law firms to provide services for their clients."},{"question":"Counseling Services","answer":"Clients are welcome to request additional services, in the event that further treatment is needed. We strive to enhance accessibility to our services. Whole Self accepts insurance, and in certain cases, we offer sliding scale services to accommodate varying financial circumstances. For more information on insurance coverage, sliding scale options, or to discuss your specific needs, please feel free to contact our agency. We are here to assist you in finding the support that aligns with your unique requirements and ensures a comprehensive approach to your mental health care."}]', 'Ready to get started?', 'Contact us to learn more about our immigration evaluation services and schedule a consultation.', 'Contact Us'),
('es', '2024-01-15T10:00:00Z', 1, 'Evaluaciones de Inmigracion - Whole Self Counseling', '', 'Evaluaciones de Inmigracion', 'Evaluaciones psicologicas exhaustivas usadas en casos de inmigracion para ayudar a los tribunales a determinar la elegibilidad de personas para permanecer legalmente en Estados Unidos.', 'Nuestras evaluaciones de inmigracion aportan evidencia clave del impacto del trauma en casos de asilo, visas U o T, y describen las dificultades asociadas con la deportacion de un familiar.', '[{"id":"political-asylum","title":"Asilo Politico","description":"Para personas que solicitan asilo por maltrato o abuso relacionado con creencias politicas, afiliacion religiosa, identidad etnica o genero en su pais de origen."},{"id":"vawa","title":"Ley de Violencia contra las Mujeres (VAWA)","description":"Para personas sin documentacion que han sufrido abuso por parte de su conyuge ciudadano/a estadounidense."},{"id":"u-visa","title":"Visa U","description":"Para victimas de delitos violentos en EE. UU. que han sufrido dano mental o fisico y colaboran con las autoridades."},{"id":"t-visa","title":"Visa T","description":"Para victimas de trata de personas (y su familia inmediata) dispuestas a colaborar con las autoridades."},{"id":"hardship-waivers","title":"Exenciones por Dificultad Extrema","description":"Para ciudadanos o residentes de EE. UU. que solicitan una exencion debido a la dificultad extrema causada por la deportacion de un familiar."}]', '[{"question":"Proceso de Evaluacion","paragraphs":["La evaluacion de inmigracion incluye entrevistas en profundidad durante dos o tres sesiones (segun las necesidades de la persona), cubriendo historia personal, conyugal, familiar, laboral, medica y psiquiatrica.","Las evaluaciones objetivas pueden incluir encuestas de TEPT, inventarios de personalidad, medidas de estado mental, auto-reportes de diversas condiciones, inventarios de salud, encuestas de violencia de pareja, medidas de conducta violenta y evaluaciones de logros. El resultado final es una evaluacion psicologica integral de 6 a 10 paginas."]},{"question":"Informacion del Evaluador","answer":"Nuestra practica cuenta con un equipo de terapeutas BIPOC (personas Negras, Indigenas y de Color) con amplia experiencia trabajando con comunidades inmigrantes. Nuestro diverso grupo de terapeutas comprende los desafios unicos de distintas culturas y esta comprometido con brindar apoyo de salud mental culturalmente sensible e inclusivo. Creemos en crear un espacio acogedor y afirmativo donde las personas se sientan comprendidas, respetadas y apoyadas en su camino hacia el bienestar."},{"question":"Servicios de Interpretacion","answer":"Las personas pueden traer interpretes y, si necesitan uno, Whole Self puede ayudar a identificarlo por un costo adicional."},{"question":"Costo y Duracion","answer":"Salvo circunstancias especiales, las evaluaciones de inmigracion cuestan $500. La mayoria se completa dentro de dos semanas despues de la entrevista final."},{"question":"Seguro","answer":"En Whole Self, entendemos la importancia de la accesibilidad a los servicios de salud mental. Segun las circunstancias, podemos facturar a las aseguradoras por los servicios brindados. Es importante tener en cuenta que las personas seran responsables de cubrir cualquier saldo no pagado por las aseguradoras. Estamos comprometidos a explorar opciones disponibles para que el apoyo en salud mental sea lo mas accesible posible. Contacta a nuestro equipo para mas detalles y ayuda con la cobertura."},{"question":"Importancia de la Evaluacion","paragraphs":["Las evaluaciones psicologicas aumentan significativamente las posibilidades de permanecer en Estados Unidos. Estudios recientes indican un 75.4% de resultado positivo para solicitantes con evaluaciones, comparado con la tasa nacional de asilo de 42.4%.","Source: Holly G. Atkinson, Katarzyna Wyka, Kathryn Hampton, Christian L. Seno, Elizabeth T. Yim, Deborah Ottenheimer, Nermeen S. Arastu, Impact of forensic medical evaluations on immigration relief grant rates and correlates of outcomes in the United States, Journal of Forensic and Legal Medicine, Volume 84, 2021, 102272, ISSN 1752-928X, https://doi.org/10.1016/j.jflm.2021.102272."],"isSource":true},{"question":"Trabajo con Firmas Legales","answer":"Colaboramos tanto con personas individuales como con firmas legales para atender a sus clientes."},{"question":"Servicios de Consejeria","answer":"Las personas pueden solicitar servicios adicionales si necesitan mas tratamiento. Nos esforzamos por mejorar la accesibilidad. Whole Self acepta seguro y, en ciertos casos, ofrece tarifas escalonadas para adaptarse a diferentes circunstancias financieras. Para mas informacion sobre cobertura de seguros, tarifas escalonadas o para hablar de tus necesidades, contacta a nuestra agencia. Estamos aqui para ayudarte a encontrar el apoyo adecuado."}]', '¿Listo para comenzar?', 'Contactanos para conocer mas sobre nuestros servicios de evaluacion de inmigracion y programar una consulta.', 'Contactanos')
ON DUPLICATE KEY UPDATE meta_last_updated=VALUES(meta_last_updated), meta_version=VALUES(meta_version), seo_title=VALUES(seo_title), seo_description=VALUES(seo_description), hero_title=VALUES(hero_title), hero_description=VALUES(hero_description), intro_text=VALUES(intro_text), specializations_json=VALUES(specializations_json), faq_json=VALUES(faq_json), cta_title=VALUES(cta_title), cta_subtitle=VALUES(cta_subtitle), cta_button_text=VALUES(cta_button_text), updated_at=NOW();
